async (params, browser) => {
  // Open Strava page
  await browser.open(`https://www.strava.com/activities/${params.activity_id}`)

  // Wait for page
  await browser.waitForSelector('.activity-summary, .heading, h1, [class*="Activity"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const title = document.querySelector('h1, .activity-name, .heading span')?.textContent?.trim() || ''; const type = document.querySelector('[class*="activity-type"], .activity-type-icon + span')?.textContent?.trim() || ''; const stats = {}; document.querySelectorAll('.inline-stats li, .stat, [class*="Stat"]').forEach(s => { const label = s.querySelector('.label, .stat-subtext, dt')?.textContent?.trim()?.toLowerCase() || ''; const value = s.querySelector('.stat, .stat-text, dd, strong')?.textContent?.trim() || ''; if (label) stats[label] = value; }); const kudos = document.querySelector('[data-testid="kudos_count"], .kudos-count, button[class*="kudo"] span')?.textContent?.trim() || '0'; return { title, type, stats, kudos, url: window.location.href };`)

  return result
}
